    ops = ['DinnerPlates']
    args = [[cap]]
    pushed = 0
    for _ in range(max(1, size)):
        r = rng.random()
        if r < 0.5:
            pushed += 1
            ops.append('push'); args.append([rng.randint(1, 1000)])
        elif r < 0.75:
            ops.append('pop'); args.append([])
        else:
            ops.append('popAtStack'); args.append([rng.randint(0, max(0, pushed // max(1, cap) + 1))])
    return [ops, args]

