import heapq


class DinnerPlates:
    def __init__(self, capacity):
        self.cap = capacity
        self.stacks = []
        self.avail = []
    def push(self, val):
        while self.avail and (self.avail[0] >= len(self.stacks) or len(self.stacks[self.avail[0]]) >= self.cap):
            heapq.heappop(self.avail)
        if self.avail:
            i = self.avail[0]
            self.stacks[i].append(val)
            if len(self.stacks[i]) == self.cap:
                heapq.heappop(self.avail)
        else:
            self.stacks.append([val])
            if self.cap > 1:
                heapq.heappush(self.avail, len(self.stacks) - 1)
    def pop(self):
        while self.stacks and not self.stacks[-1]:
            self.stacks.pop()
        if not self.stacks:
            return -1
        return self.popAtStack(len(self.stacks) - 1)
    def popAtStack(self, index):
        if index >= len(self.stacks) or not self.stacks[index]:
            return -1
        v = self.stacks[index].pop()
        heapq.heappush(self.avail, index)
        return v

