class MinHeap {
    constructor() { this.a = []; }
    push(x) { const a = this.a; a.push(x); let i = a.length - 1; while (i > 0) { const p = (i - 1) >> 1; if (a[p] <= a[i]) break; [a[p], a[i]] = [a[i], a[p]]; i = p; } }
    top() { return this.a[0]; }
    size() { return this.a.length; }
    pop() { const a = this.a; const top = a[0]; const last = a.pop(); if (a.length) { a[0] = last; let i = 0; const n = a.length; while (true) { let l = 2 * i + 1, r = 2 * i + 2, s = i; if (l < n && a[l] < a[s]) s = l; if (r < n && a[r] < a[s]) s = r; if (s === i) break; [a[s], a[i]] = [a[i], a[s]]; i = s; } } return top; }
}
var DinnerPlates = function(capacity) {
    this.cap = capacity;
    this.stacks = [];
    this.avail = new MinHeap();
};
DinnerPlates.prototype.push = function(val) {
    while (this.avail.size() && (this.avail.top() >= this.stacks.length || this.stacks[this.avail.top()].length >= this.cap)) this.avail.pop();
    if (this.avail.size()) {
        const i = this.avail.top();
        this.stacks[i].push(val);
        if (this.stacks[i].length === this.cap) this.avail.pop();
    } else {
        this.stacks.push([val]);
        if (this.cap > 1) this.avail.push(this.stacks.length - 1);
    }
};
DinnerPlates.prototype.pop = function() {
    while (this.stacks.length && this.stacks[this.stacks.length - 1].length === 0) this.stacks.pop();
    if (!this.stacks.length) return -1;
    return this.popAtStack(this.stacks.length - 1);
};
DinnerPlates.prototype.popAtStack = function(index) {
    if (index >= this.stacks.length || this.stacks[index].length === 0) return -1;
    const v = this.stacks[index].pop();
    this.avail.push(index);
    return v;
};
